mapper.select:
SELECT * FROM medir_roster_weekend_stat
WHERE roster_week_id = #{rosterWeekId}
ORDER BY staff_id

mapper.insert:
INSERT INTO medir_roster_weekend_stat (
    roster_week_id, staff_id, weekend_full_override, last_weekend_override, override_reason
) VALUES (
    #{rosterWeekId}, #{staffId}, #{weekendFullOverride}, #{lastWeekendOverride}, #{overrideReason}
)
ON DUPLICATE KEY UPDATE
    weekend_full_override = VALUES(weekend_full_override),
    last_weekend_override = VALUES(last_weekend_override),
    override_reason = VALUES(override_reason)
